mapper.select:
SELECT file_path
                                                       FROM post_files
                                                       WHERE post_id = #{postId}

mapper.update:
UPDATE posts
                                    SET view_count = view_count + 1
                                    WHERE post_id = #{postId}

mapper.delete:
DELETE
                                FROM post_files
                                WHERE file_path = #{s3key}
                                  AND post_id = #{postId}

mapper.update:
UPDATE posts
                            SET title      = #{title},
                                content    = #{content},
                                updated_at = NOW(),
                                is_notice  =
                                    #{isNotice}
                            WHERE post_id = #{postId}
                              and user_id = #{userId}

